svg.script:

let initValue = 0;
//!export-start
let _pn_value = initValue;
let _pn_min = 0;
let _pn_max = 360;
let _pn_animationMs = 700;
let _pc_outerColor = "#d9d9d9ff";
let _pc_dialColor = "#b53234ff";
let _pc_tickColor = "#f2f2f2ff";
let _pc_textColor = "#f2f2f2ff";
let _pc_markerColor = "#b76a4eff";
let _pc_centerColor = "#eeeeeeff";
let _pn_labelSize = 12;
let _pn_tickWidth = 1.3;
//!export-end

let compassTimer = null;
let compassWatchTimer = null;
let compassCurrentAngle = 0;
let compassTargetValue = null;

function init() {
  applyCompassStyle();
  compassCurrentAngle = valueToDialAngle(_pn_value);
  compassTargetValue = normalizeValue(_pn_value);
  setDialAngle(compassCurrentAngle);
}

function applyCompassStyle() {
  setAttrSafe('outerRing', 'fill', _pc_outerColor);
  setAttrSafe('dialBackground', 'fill', _pc_dialColor);
  setAttrSafe('topMarker', 'stroke', _pc_markerColor);
  setAttrSafe('centerCap', 'fill', _pc_centerColor);
  setAttrSafe('labelLayer', 'fill', _pc_textColor);
  setAttrSafe('labelLayer', 'font-size', _pn_labelSize);

  const root = getSvgRoot();
  const ticks = root ? root.querySelectorAll('[data-major]') : [];
  for (let i = 0; i < ticks.length; i++) {
    const width = ticks[i].getAttribute('data-major') === '1' ? _pn_tickWidth * 1.8 : _pn_tickWidth;
    ticks[i].setAttribute('stroke', _pc_tickColor);
    ticks[i].setAttribute('stroke-width', width);
  }
}

function normalizeValue(value) {
  let num = parseFloat(value);
  if (isNaN(num)) { num = 0; }
  const min = parseFloat(_pn_min);
  const max = parseFloat(_pn_max);
  const safeMin = isNaN(min) ? 0 : min;
  const safeMax = isNaN(max) || max === safeMin ? 360 : max;
  const clamped = Math.max(safeMin, Math.min(safeMax, num));
  return ((clamped - safeMin) / (safeMax - safeMin)) * 360;
}

function valueToDialAngle(value) {
  return -normalizeDegree(value);
}

function normalizeDegree(value) {
  let degree = parseFloat(value);
  if (isNaN(degree)) { degree = 0; }
  degree = degree % 360;
  return degree < 0 ? degree + 360 : degree;
}

function animateDialTo(targetAngle) {
  if (compassTimer) { clearInterval(compassTimer); }
  const startAngle = compassCurrentAngle;
  const deltaAngle = shortestAngleDelta(startAngle, targetAngle);
  const duration = Math.max(0, parseFloat(_pn_animationMs) || 0);
  const startTime = Date.now();
  if (duration === 0) {
    compassCurrentAngle = startAngle + deltaAngle;
    setDialAngle(compassCurrentAngle);
    return;
  }
  compassTimer = setInterval(function () {
    const progress = Math.min(1, (Date.now() - startTime) / duration);
    const eased = easeOutCubic(progress);
    compassCurrentAngle = startAngle + (deltaAngle * eased);
    setDialAngle(compassCurrentAngle);
    if (progress >= 1) {
      clearInterval(compassTimer);
      compassTimer = null;
      compassCurrentAngle = startAngle + deltaAngle;
      setDialAngle(compassCurrentAngle);
    }
  }, 16);
}

function shortestAngleDelta(fromAngle, toAngle) {
  return ((toAngle - fromAngle + 540) % 360) - 180;
}

function easeOutCubic(value) {
  const inv = 1 - value;
  return 1 - inv * inv * inv;
}

function setDialAngle(angle) {
  const dial = getSvgElement('dial');
  if (dial) {
    dial.setAttribute('transform', 'rotate(' + angle + ' 100 100)');
  }
}

function getSvgRoot() {
  const dial = document.getElementById('compassDial');
  if (dial && dial.ownerSVGElement) { return dial.ownerSVGElement; }
  const outer = document.getElementById('outerRing');
  if (outer && outer.ownerSVGElement) { return outer.ownerSVGElement; }
  const allSvg = document.getElementsByTagName('svg');
  return allSvg && allSvg.length ? allSvg[allSvg.length - 1] : null;
}

function getSvgElement(name) {
  if (name === 'dial') {
    const dial = document.getElementById('compassDial');
    if (dial) { return dial; }
  }

  const byId = document.getElementById(name);
  if (byId) { return byId; }

  const root = getSvgRoot();
  if (!root || !root.querySelector) { return null; }
  return root.querySelector('[data-compass="' + name + '"]');
}

function setAttrSafe(name, attr, value) {
  const element = getSvgElement(name);
  if (element) { element.setAttribute(attr, value); }
}

function setNumericValue(value) {
  const normalizedValue = normalizeValue(value);
  _pn_value = parseFloat(value);
  if (isNaN(_pn_value)) { _pn_value = 0; }
  compassTargetValue = normalizedValue;
  animateDialTo(valueToDialAngle(normalizedValue));
}

function putValue(id, value) {
  switch (id) {
    case '_pn_value':
      setNumericValue(value);
      break;
    case '_pn_min':
      _pn_min = parseFloat(value);
      setNumericValue(_pn_value);
      break;
    case '_pn_max':
      _pn_max = parseFloat(value);
      setNumericValue(_pn_value);
      break;
    case '_pn_animationMs':
      _pn_animationMs = parseFloat(value);
      break;
    case '_pc_outerColor':
      _pc_outerColor = value;
      applyCompassStyle();
      break;
    case '_pc_dialColor':
      _pc_dialColor = value;
      applyCompassStyle();
      break;
    case '_pc_tickColor':
      _pc_tickColor = value;
      applyCompassStyle();
      break;
    case '_pc_textColor':
      _pc_textColor = value;
      applyCompassStyle();
      break;
    case '_pc_markerColor':
      _pc_markerColor = value;
      applyCompassStyle();
      break;
    case '_pc_centerColor':
      _pc_centerColor = value;
      applyCompassStyle();
      break;
    case '_pn_labelSize':
      _pn_labelSize = parseFloat(value);
      applyCompassStyle();
      break;
    case '_pn_tickWidth':
      _pn_tickWidth = parseFloat(value);
      applyCompassStyle();
      break;
  }
}

setTimeout(function () { init(); }, 100);
